  "Delete Session": "\u5220\u9664\u4F1A\u8BDD",
  "Enable auto-update for this extension.": "\u4E3A\u6B64\u6269\u5C55\u542F\u7528\u81EA\u52A8\u66F4\u65B0\u3002",
