  // MCP Management Dialog
  // ============================================================================
  "Manage MCP servers": "\u7BA1\u7406 MCP servers",
  "Server Detail": "\u670D\u52A1\u5668\u8BE6\u60C5",
  Tools: "\u5DE5\u5177",
  "Tool Detail": "\u5DE5\u5177\u8BE6\u60C5",
  "Loading...": "\u52A0\u8F7D\u4E2D...",
  "Unknown step": "\u672A\u77E5\u6B65\u9AA4",
  "Esc to back": "Esc \u8FD4\u56DE",
  "\u2191\u2193 to navigate \xB7 Enter to select \xB7 Esc to close": "\u2191\u2193 \u5BFC\u822A \xB7 Enter \u9009\u62E9 \xB7 Esc \u5173\u95ED",
  "\u2191\u2193 to navigate \xB7 Enter to select \xB7 Esc to back": "\u2191\u2193 \u5BFC\u822A \xB7 Enter \u9009\u62E9 \xB7 Esc \u8FD4\u56DE",
  "\u2191\u2193 to navigate \xB7 Enter to confirm \xB7 Esc to back": "\u2191\u2193 \u5BFC\u822A \xB7 Enter \u786E\u8BA4 \xB7 Esc \u8FD4\u56DE",
