  "Raw mode not available. Please run in an interactive terminal.": "\u539F\u59CB\u6A21\u5F0F\u4E0D\u53EF\u7528\u3002\u8BF7\u5728\u4EA4\u4E92\u5F0F\u7EC8\u7AEF\u4E2D\u8FD0\u884C\u3002",
  "(Use \u2191 \u2193 arrows to navigate, Enter to select, Ctrl+C to exit)\n": "(\u4F7F\u7528 \u2191 \u2193 \u7BAD\u5934\u5BFC\u822A\uFF0CEnter \u9009\u62E9\uFF0CCtrl+C \u9000\u51FA)\n",
  "Hide tool output and thinking for a cleaner view (toggle with Ctrl+O).": "\u7D27\u51D1\u6A21\u5F0F\u4E0B\u9690\u85CF\u5DE5\u5177\u8F93\u51FA\u548C\u601D\u8003\u8FC7\u7A0B\uFF0C\u754C\u9762\u66F4\u7B80\u6D01\uFF08Ctrl+O \u5207\u6362\uFF09\u3002",
  "Press Ctrl+O to show full tool output": "\u6309 Ctrl+O \u67E5\u770B\u8BE6\u7EC6\u5DE5\u5177\u8C03\u7528\u7ED3\u679C",
  "Switch to plan mode or exit plan mode": "\u5207\u6362\u5230\u8BA1\u5212\u6A21\u5F0F\u6216\u9000\u51FA\u8BA1\u5212\u6A21\u5F0F",
  "Set a goal \u2014 keep working until the condition is met": "\u8BBE\u5B9A\u76EE\u6807 \u2014 \u6301\u7EED\u5DE5\u4F5C\u76F4\u5230\u6761\u4EF6\u6EE1\u8DB3",
  "Exited plan mode. Previous approval mode restored.": "\u5DF2\u9000\u51FA\u8BA1\u5212\u6A21\u5F0F\uFF0C\u5DF2\u6062\u590D\u4E4B\u524D\u7684\u5BA1\u6279\u6A21\u5F0F\u3002",
  "Enabled plan mode. The agent will analyze and plan without executing tools.": "\u542F\u7528\u8BA1\u5212\u6A21\u5F0F\u3002\u667A\u80FD\u4F53\u5C06\u53EA\u5206\u6790\u548C\u89C4\u5212\uFF0C\u800C\u4E0D\u6267\u884C\u5DE5\u5177\u3002",
  'Already in plan mode. Use "/plan exit" to exit plan mode.': '\u5DF2\u5904\u4E8E\u8BA1\u5212\u6A21\u5F0F\u3002\u4F7F\u7528 "/plan exit" \u9000\u51FA\u8BA1\u5212\u6A21\u5F0F\u3002',
  'Not in plan mode. Use "/plan" to enter plan mode first.': '\u672A\u5904\u4E8E\u8BA1\u5212\u6A21\u5F0F\u3002\u8BF7\u5148\u4F7F\u7528 "/plan" \u8FDB\u5165\u8BA1\u5212\u6A21\u5F0F\u3002',
  "Set up Qwen Code's status line UI": "\u914D\u7F6E Qwen Code \u7684\u72B6\u6001\u680F",
  // === Core: added from PR #3328 ===
  "Ask a quick side question without affecting the main conversation": "\u5728\u4E0D\u5F71\u54CD\u4E3B\u5BF9\u8BDD\u7684\u60C5\u51B5\u4E0B\u5FEB\u901F\u95EE\u4E00\u4E2A\u65C1\u652F\u95EE\u9898",
  "Manage Arena sessions": "\u7BA1\u7406 Arena \u4F1A\u8BDD",
  "Start an Arena session with multiple models competing on the same task": "\u542F\u52A8\u4E00\u4E2A Arena \u4F1A\u8BDD\uFF0C\u8BA9\u591A\u4E2A\u6A21\u578B\u5728\u540C\u4E00\u4EFB\u52A1\u4E0A\u7ADE\u4E89",
  "Stop the current Arena session": "\u505C\u6B62\u5F53\u524D Arena \u4F1A\u8BDD",
  "Show the current Arena session status": "\u663E\u793A\u5F53\u524D Arena \u4F1A\u8BDD\u72B6\u6001",
  "Select a model result and merge its diff into the current workspace": "\u9009\u62E9\u4E00\u4E2A\u6A21\u578B\u7ED3\u679C\u5E76\u5C06\u5176\u5DEE\u5F02\u5408\u5E76\u5230\u5F53\u524D\u5DE5\u4F5C\u533A",
  "No running Arena session found.": "\u672A\u627E\u5230\u6B63\u5728\u8FD0\u884C\u7684 Arena \u4F1A\u8BDD\u3002",
  "No Arena session found. Start one with /arena start.": "\u672A\u627E\u5230 Arena \u4F1A\u8BDD\u3002\u8BF7\u4F7F\u7528 /arena start \u542F\u52A8\u4E00\u4E2A\u3002",
  "Arena session is still running. Wait for it to complete or use /arena stop first.": "Arena \u4F1A\u8BDD\u4ECD\u5728\u8FD0\u884C\u4E2D\u3002\u8BF7\u7B49\u5F85\u5176\u5B8C\u6210\uFF0C\u6216\u5148\u4F7F\u7528 /arena stop\u3002",
  "No successful agent results to select from. All agents failed or were cancelled.": "\u6CA1\u6709\u53EF\u9009\u62E9\u7684\u6210\u529F\u667A\u80FD\u4F53\u7ED3\u679C\u3002\u6240\u6709\u667A\u80FD\u4F53\u5747\u5931\u8D25\u6216\u88AB\u53D6\u6D88\u3002",
  "Use /arena stop to end the session.": "\u4F7F\u7528 /arena stop \u7ED3\u675F\u4F1A\u8BDD\u3002",
  'No idle agent found matching "{{name}}".': '\u672A\u627E\u5230\u5339\u914D "{{name}}" \u7684\u7A7A\u95F2\u667A\u80FD\u4F53\u3002',
  "Failed to apply changes from {{label}}: {{error}}": "\u4ECE {{label}} \u5E94\u7528\u66F4\u6539\u5931\u8D25\uFF1A{{error}}",
  "Applied changes from {{label}} to workspace. Arena session complete.": "\u5DF2\u5C06 {{label}} \u7684\u66F4\u6539\u5E94\u7528\u5230\u5DE5\u4F5C\u533A\u3002Arena \u4F1A\u8BDD\u5B8C\u6210\u3002",
  "Discard all Arena results and clean up worktrees?": "\u4E22\u5F03\u6240\u6709 Arena \u7ED3\u679C\u5E76\u6E05\u7406\u5DE5\u4F5C\u6811\uFF1F",
  "Arena results discarded. All worktrees cleaned up.": "Arena \u7ED3\u679C\u5DF2\u4E22\u5F03\u3002\u6240\u6709\u5DE5\u4F5C\u6811\u5DF2\u6E05\u7406\u3002",
  "Arena is not supported in non-interactive mode. Use interactive mode to start an Arena session.": "Arena \u4E0D\u652F\u6301\u975E\u4EA4\u4E92\u6A21\u5F0F\u3002\u8BF7\u4F7F\u7528\u4EA4\u4E92\u6A21\u5F0F\u542F\u52A8 Arena \u4F1A\u8BDD\u3002",
  "Arena is not supported in non-interactive mode. Use interactive mode to stop an Arena session.": "Arena \u4E0D\u652F\u6301\u975E\u4EA4\u4E92\u6A21\u5F0F\u3002\u8BF7\u4F7F\u7528\u4EA4\u4E92\u6A21\u5F0F\u505C\u6B62 Arena \u4F1A\u8BDD\u3002",
  "Arena is not supported in non-interactive mode.": "Arena \u4E0D\u652F\u6301\u975E\u4EA4\u4E92\u6A21\u5F0F\u3002",
  "An Arena session exists. Use /arena stop or /arena select to end it before starting a new one.": "\u5DF2\u5B58\u5728 Arena \u4F1A\u8BDD\u3002\u8BF7\u4F7F\u7528 /arena stop \u6216 /arena select \u7ED3\u675F\u540E\u518D\u542F\u52A8\u65B0\u4F1A\u8BDD\u3002",
  "Usage: /arena start --models model1,model2 <task>": "\u7528\u6CD5\uFF1A/arena start --models model1,model2 <task>",
  "Models to compete (required, at least 2)": "\u53C2\u4E0E\u7ADE\u4E89\u7684\u6A21\u578B\uFF08\u5FC5\u987B\uFF0C\u81F3\u5C11 2 \u4E2A\uFF09",
  "Format: authType:modelId or just modelId": "\u683C\u5F0F\uFF1AauthType:modelId \u6216\u4EC5 modelId",
  "Arena requires at least 2 models. Use --models model1,model2 to specify.": "Arena \u81F3\u5C11\u9700\u8981 2 \u4E2A\u6A21\u578B\u3002\u8BF7\u4F7F\u7528 --models model1,model2 \u6307\u5B9A\u3002",
  'Arena started with {{count}} agents on task: "{{task}}"\nModels:\n{{modelList}}': 'Arena \u5DF2\u542F\u52A8 {{count}} \u4E2A\u667A\u80FD\u4F53\u5904\u7406\u4EFB\u52A1\uFF1A"{{task}}"\n\u6A21\u578B\uFF1A\n{{modelList}}',
  "Arena panes are running in tmux. Attach with: `{{command}}`": "Arena \u9762\u677F\u6B63\u5728 tmux \u4E2D\u8FD0\u884C\u3002\u4F7F\u7528\u4EE5\u4E0B\u547D\u4EE4\u9644\u52A0\uFF1A`{{command}}`",
  "[{{label}}] failed: {{error}}": "[{{label}}] \u5931\u8D25\uFF1A{{error}}",
  "Loading suggestions...": "\u6B63\u5728\u52A0\u8F7D\u5EFA\u8BAE...",
  "Open the memory manager.": "\u6253\u5F00\u8BB0\u5FC6\u7BA1\u7406\u5668\u3002",
  "Show current process memory diagnostics": "\u663E\u793A\u5F53\u524D\u8FDB\u7A0B\u7684\u5185\u5B58\u8BCA\u65AD\u3002",
  "Record a CPU profile for Chrome DevTools analysis": "\u5F55\u5236 CPU \u6027\u80FD\u5206\u6790\u6587\u4EF6\uFF0C\u7528\u4E8E Chrome DevTools \u5206\u6790",
  "Roll back a standalone update to the previous version": "\u5C06\u72EC\u7ACB\u5B89\u88C5\u56DE\u6EDA\u5230\u4E0A\u4E00\u4E2A\u7248\u672C",
  "Rollback is not available in ACP mode.": "\u56DE\u6EDA\u5728 ACP \u6A21\u5F0F\u4E0B\u4E0D\u53EF\u7528\u3002",
  "Rollback is only available for standalone installations.": "\u56DE\u6EDA\u4EC5\u9002\u7528\u4E8E\u72EC\u7ACB\u5B89\u88C5\u3002",
  "Rollback successful. Restart your terminal to use the previous version.": "\u56DE\u6EDA\u6210\u529F\u3002\u8BF7\u91CD\u542F\u7EC8\u7AEF\u4EE5\u4F7F\u7528\u4E0A\u4E00\u4E2A\u7248\u672C\u3002",
  "Rollback failed:": "\u56DE\u6EDA\u5931\u8D25\uFF1A",
  "Rollback on Windows requires manual intervention. Rename qwen-code.old to qwen-code in your installation directory.": "\u5728 Windows \u4E0A\u56DE\u6EDA\u9700\u8981\u624B\u52A8\u64CD\u4F5C\u3002\u8BF7\u5C06\u5B89\u88C5\u76EE\u5F55\u4E2D\u7684 qwen-code.old \u91CD\u547D\u540D\u4E3A qwen-code\u3002",
  "Save a durable memory to the memory system.": "\u5C06\u4E00\u6761\u6301\u4E45\u8BB0\u5FC6\u4FDD\u5B58\u5230\u8BB0\u5FC6\u7CFB\u7EDF\u3002",
  "Show per-item context usage breakdown.": "\u663E\u793A\u6309\u9879\u76EE\u5212\u5206\u7684\u4E0A\u4E0B\u6587\u4F7F\u7528\u8BE6\u60C5\u3002",
